using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 renamed the JSON discriminator from "Discriminator" to "$type".
            // Keep the old name so existing 500K documents and direct SQL queries
            // that reference c.Discriminator continue to work.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 no longer embeds the discriminator in the JSON id property.
            // Existing documents use the "Product|<key>" format — preserve it.
            b.HasDiscriminatorInJsonId();

            // EF9 maps the key property directly to the JSON "id" instead of
            // using a shadow __id property. Existing documents store the key
            // under a separate JSON property, so keep the shadow id.
            b.HasShadowId();
        });

        // Removed: HasIndex — EF9 Cosmos provider now throws because
        // Cosmos DB indexes all properties by default.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

